const SetValue = async (context) => {
   const qty = parseFloat(context?.Form?.MeasureQty?.Value) || 0;
   const measureType = context?.Form?.WorkOrderMeasureType?.Text || "";
   const repairCost = parseFloat(context?.Form?.MeasureRepairCost?.Value) || 0;
   const incentive = parseFloat(context?.Form?.MeasureCost?.Value) || 0;
   const incentiveOverride = parseFloat(context?.Form?.IncentiveOverride?.Value) || 0;
   const auditMeasure = parseFloat(context?.Form?.AuditMeasureInstallationCost?.Value) || 0;
   const status = context?.Form?.MeasureStatus?.Value || "";

   // Priority to check if measure is included or not from historical import
   if (status == "REJECTED") {
       return 0;
   }
   // If incentive override has a value, use it (highest priority - master override)
   if (incentiveOverride > 0) {
       return incentiveOverride;
   }

   // If audit measure has a value, use it (second priority override)
   if (auditMeasure > 0) {
       return auditMeasure;
   }

   // If repair cost has a value, use repair cost calculation
   if (repairCost > 0) {
       return qty * repairCost;
   }

   // If measure type includes "Home Repair" or "Appliance Repair", use repair cost calculation
   if (measureType.includes("Home Repair") || measureType.includes("Appliance Repair")) {
       return qty * repairCost;
   }

   // Default calculation using incentive cost
   return qty * incentive;
