const SetValue = async (context) => {
    // Get income values and ensure they're parsed as numbers
    const incomeTotalStr = context?.Form?.ApplicantInformationPage?.HouseholdTotalGrossIncome?.Value || "0";
    const thresholdStr = context?.Form?.ApplicantInformationPage?.IncomeThreshold?.Value || "0";

    // Parse removing any commas, dollar signs or other formatting
    const incomeTotal = parseFloat(incomeTotalStr.toString().replace(/[$,]/g, "")) || 0;
    const threshold = parseFloat(thresholdStr.toString().replace(/[$,]/g, "")) || 0;

    // Calculate if income is within threshold
    if (threshold > 0) {
        if (incomeTotal <= threshold) {
            return "Eligible";
        } else {
            return "Over Income";
        }
    }

    // Return empty string if threshold is 0 or not found
    return "";
}","ClearValueOnTrue":false,"ClearValueOnFalse":false,"Key":null,"Fields":[{"ModelKey":"Form.ApplicantInformationPage.HouseholdTotalGrossIncome","FieldName":"HouseholdTotalGrossIncome","IsSystemModelKey":false},{"ModelKey":"Form.ApplicantInformationPage.IncomeThreshold","FieldName":"IncomeThreshold","IsSystemModelKey":false}]}

