{"Configuration":"/** @param {Context} context */
const SetValue = async (context) => {

    // Extract address components with safety checks
    const street = context.Form.Page1.SiteAddressStreet1.Value || "";
    const city = context.Form.Page1.SiteAddressCity.Value || "";
    const zipCode = context.Form.Page1.SiteAddressZipcode.Value || "";

    // Define a map for common directional prefixes and street suffixes to their standardized forms
    const directionMap = {
        'N': 'N',
        'S': 'S',
        'E': 'E',
        'W': 'W',
        'NE': 'NE',
        'NW': 'NW',
        'SE': 'SE',
        'SW': 'SW',
        'NORTH': 'N',
        'SOUTH': 'S',
        'EAST': 'E',
        'WEST': 'W',
        'NORTHEAST': 'NE',
        'NORTHWEST': 'NW',
        'SOUTHEAST': 'SE',
        'SOUTHWEST': 'SW'
    };

    const suffixMap = {
        'ST': 'ST',
        'STREET': 'ST',
        'RD': 'RD',
        'ROAD': 'RD',
        'AVE': 'AVE',
        'AVENUE': 'AVE',
        'BLVD': 'BLVD',
        'BOULEVARD': 'BLVD',
        'DR': 'DR',
        'DRIVE': 'DR',
        'CT': 'CT',
        'COURT': 'CT',
        'CIR': 'CIR',
        'CIRCLE': 'CIR',
        'LN': 'LN',
        'LANE': 'LN'
        // Add more suffixes as needed
    };

    // Standardize and clean the street address
    let cleanStreet = street
        .replace(/\b(N|S|E|W|NE|NW|SE|SW|NORTH|SOUTH|EAST|WEST|NORTHEAST|NORTHWEST|SOUTHEAST|SOUTHWEST)\b/gi, match => directionMap[match.toUpperCase()] || '')
        .replace(/\b(ST|STREET|RD|ROAD|AVE|AVENUE|BLVD|BOULEVARD|DR|DRIVE|CT|COURT|LN|LANE)\b/gi, match => suffixMap[match.toUpperCase()] || match)
        .replace(/[\s.,]+/g, '') // Remove spaces, periods, commas
        .toUpperCase();

    // Clean the city and zip code
    const cleanCity = city.replace(/[\s.,]+/g, '').toUpperCase();
    const cleanZipCode = zipCode.replace(/[\s.,]+/g, '').toUpperCase();

    // Combine the cleaned components into the SiteID
    const siteID = `${cleanStreet}${cleanCity}${cleanZipCode}`;

    // Return the computed SiteID
    return siteID.trim();
}
